hound.on('email.send', handler, { queue: 'emails' });
hound.on('report.generate', handler, { queue: 'heavy' });
hound.on('analytics.track', handler); // uses 'default' queue

const hound = Hound.create({
  db: redis,
  concurrency: 20, // global max across all handlers
});

hound.on('email.send', handler, {
  concurrency: 5, // max 5 concurrent email sends
});

const hound = Hound.create({
  db: redis,
  processor: {
    queuePriority: {
      critical: 1,
      default: 2,
      heavy: 3,
    },
  },
});

hound.on('search.reindex', handler, {
  debounce: 2_000, // only run once per 2s burst
});

const mgmt = new HoundManagement({ db: redis, hound });

await mgmt.api.queues.pause('heavy');
// ... maintenance window ...
await mgmt.api.queues.resume('heavy');
